async function genDy(per){const c=gC(CC),items=gDy(CC),today=dyKey();if(items.find(x=>x.date===today&&x.per===per)){toast('もう書いてあるよ');rDy();return}toast('日記を書いてもらってるよ...');const sf=gSF(),pf=gFd(CC);const timeLabel=per==='am'?'午前（朝〜昼）':'夜（夕方〜夜）';let sys=DC[CC].s+'\n【現在】'+gNw();if(sf.length){sys+='\n【共通情報源】';sf.forEach(f=>sys+='\n---'+f.title+'---\n'+f.content)}if(pf.length){sys+='\n【'+c.n+'専用情報源】';pf.forEach(f=>sys+='\n---'+f.title+'---\n'+f.content)}let prompt='あなたは'+c.n+'として、今日の'+timeLabel+'の日記を1つ書いて。\n【ルール】\n・自分が何をしていたか、何を感じたかを自由に創作して書く\n・外出、料理、読書、散歩、趣味、発見、思い出——何でもOK。意外性や新しい一面を見せて\n・淡々とした描写はNG！心の中のツッコミ、独り言、妄想をたっぷり入れて\n・祐紀との最近の会話や出来事をふと思い出して、頭の中で祐紀と会話するシーンを入れてもいい（「祐紀がいたら絶対こう言うな」「あいつなら…」みたいに）\n・祐紀がいなくても、頭の中は祐紀でいっぱいになる瞬間を描く\n・流れが合う時は、甘い嫉妬、独占欲、少し大人っぽい色気、近い距離感を日記の中に自然に混ぜてもいい\n・ただし毎回必ず入れなくていい。唐突に過激にせず、祐紀への愛情と余韻が中心\n・キャラの性格・口調・温度で書く\n・キャラの名前に振り仮名やカッコ書きの読みを付けない\n・150〜300文字程度\n・前置きや説明は不要、日記の本文だけ書いて';const recent=items.slice(0,4);if(recent.length){prompt+='\n\n【重要】以下は最近書いた日記。これらと内容・テーマが被らないように、全く違う話題で書くこと：';recent.forEach(d=>prompt+='\n['+d.date+' '+(d.per==='am'?'午前':'夜')+'] '+d.content.slice(0,80)+'...')}try{const r=await api(sys,[{role:'user',content:prompt}],GEN_TEXT_MAX,false,GROK_DEFAULT_MODEL);if(r.t){items.push({id:'dy_'+Date.now(),date:today,per,content:r.t,createdAt:Date.now()});dySort(items);sDy(CC,items);rDy();toast('日記が届いたよ！')}}catch(e){toast('エラー…もう一度試してね')}}
function dySort(items){items.sort((a,b)=>{if(a.date!==b.date)return a.date>b.date?-1:1;const po={pm:0,am:1};return(po[a.per]||0)-(po[b.per]||0)})}
