function rNj(){const el=document.getElementById('nLL');el.innerHTML='';const items=gNj(CC);const today=dyKey();const hasChat=items.find(x=>x.date===today&&x.tp==='chat');const hasFree=items.find(x=>x.date===today&&x.tp==='free');const hasUni=items.find(x=>x.date===today&&x.tp==='uni');const hasDiary=items.find(x=>x.date===today&&x.tp==='diary');document.getElementById('njBtnChat').style.display=hasChat?'none':'';document.getElementById('njBtnFree').style.display=hasFree?'none':'';document.getElementById('njBtnUni').style.display=hasUni?'none':'';const ydItems=gYD();document.getElementById('njBtnDiary').style.display=(hasDiary||!ydItems.length)?'none':'';document.getElementById('njBtnHG').style.display=gHG().length?'':'none';if(!items.length){el.innerHTML='<div class="dy-gen">まだ日常つづりがないよ。<br>上のボタンを押して生成しよう！</div>';return}items.forEach((it,i)=>{const div=document.createElement('div');div.className='dy'+(i===0?' open':'');const typeTxt=it.tp==='chat'?'💬 チャットから':it.tp==='uni'?'🌟 Universe':it.tp==='diary'?'📝 日記リアクション':it.tp==='hg'?'💭 ひとりごと':'✨ 自由';const preview=it.content.replace(/\n/g,' ').slice(0,30)+'…';div.innerHTML=`<div class="dy-h" onclick="this.parentElement.classList.toggle('open')"><span class="dy-date">${it.date}</span><span class="dy-per dy-am">${typeTxt}</span><span class="dy-pv">${X(preview)}</span></div><div class="dy-body"><div class="dy-txt">${X(it.content)}</div><div style="text-align:right;margin-top:8px"><button style="font-size:10px;padding:4px 10px;border-radius:6px;background:none;border:1px solid rgba(160,160,160,.3);color:var(--t3);cursor:pointer;font-family:inherit;margin-right:6px" onclick="cpNj('${it.id}')">コピー</button><button style="font-size:10px;padding:4px 10px;border-radius:6px;background:none;border:1px solid rgba(224,112,112,.3);color:#e07070;cursor:pointer;font-family:inherit" onclick="askDNj('${it.id}')">この日常つづりを削除</button></div></div>`;el.appendChild(div)})}
function askDNj(id){ask('この日常つづりを削除しますか？',()=>{const items=gNj(CC).filter(x=>x.id!==id);sNj(CC,items);rNj();toast('日常つづりを削除しました')})}
function cpNj(id){const it=gNj(CC).find(x=>x.id===id);if(!it)return;const txt=it.content;navigator.clipboard.writeText(txt).then(()=>toast('コピーしました')).catch(()=>{const ta=document.createElement('textarea');ta.value=txt;ta.style.cssText='position:fixed;opacity:0';document.body.appendChild(ta);ta.select();document.execCommand('copy');document.body.removeChild(ta);toast('コピーしました')})}
function cleanSys(s){return s.split('\n\n').filter(p=>!/雄感|えちち|雄モード|理性を手放し|身体ごと愛/.test(p)).join('\n\n')}
function clipTxt(t,max){t=(t||'').toString().trim();if(!max||t.length<=max)return t;return t.slice(0,Math.max(0,max-1))+'…'}
function appendInfoBlock(sys,title,files,perFile,totalMax){if(!files||!files.length)return sys;let used=0,block='\n【'+title+'】';for(const f of files){if(used>=totalMax)break;const head='\n---'+(f.title||'無題')+'---\n';const room=Math.max(0,totalMax-used-head.length);if(room<=80)break;const body=clipTxt(f.content||'',Math.min(perFile,room));if(!body)continue;block+=head+body;used+=head.length+body.length}return sys+block}
function buildGenSys(c,tp){let sys=(tp==='uni'?cleanSys(DC[CC].s):DC[CC].s)+'\n【現在】'+gNw();sys=clipTxt(sys,tp==='uni'?4200:5200);sys=appendInfoBlock(sys,'共通情報源',gSfOn()?gSF():[],700,tp==='uni'?1600:2200);sys=appendInfoBlock(sys,c.n+'専用情報源',gPfOn(CC)?gFd(CC):[],700,tp==='uni'?1600:2200);return sys}
function buildChatSys(c){let sys=DC[CC].s+'\n【現在】'+gNw();sys=clipTxt(sys,5600);sys=appendInfoBlock(sys,'共通情報源',gSfOn()?gSF():[],900,2400);sys=appendInfoBlock(sys,c.n+'専用情報源',gPfOn(CC)?gFd(CC):[],900,2400);const dyItems=gDy(CC).slice(0,2);if(dyItems.length){sys+='\n【'+c.n+'の最近の日記（自分が書いたもの。覚えていて自然に話題にできる）】';dyItems.forEach(d=>sys+='\n['+d.date+' '+(d.per==='am'?'午前':'夜')+']\n'+clipTxt(d.content||'',500))}const memo=clipTxt(gMm(CC),1800);if(memo)sys+='\n【'+c.n+'の祐紀メモ（これまでの会話で蓄積された重要情報）】\n'+memo;return sys}
function mkUniP(cName,exGuests,exScenes){let others=DORD.filter(id=>id!==CC&&DC[id]&&!(exGuests||[]).includes(id));if(others.length<2)others=DORD.filter(id=>id!==CC&&DC[id]);for(let i=others.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[others[i],others[j]]=[others[j],others[i]]}const guestCount=Math.random()<0.5?1:2;const guests=others.slice(0,guestCount);const guestInfo=guests.map(id=>CSUM[id]).join('\n');const guestNames=guests.map(id=>DC[id].n).join('と');const now=new Date(),mo=now.getMonth()+1,hr=now.getHours();const sn={1:'冬',2:'冬',3:'春',4:'春',5:'春',6:'梅雨',7:'夏',8:'夏',9:'秋',10:'秋',11:'秋',12:'冬'}[mo];const tp2=hr<6?'深夜':hr<10?'朝':hr<14?'昼':hr<17?'午後':hr<20?'夕方':'夜';const tones=['コメディ回（笑いとツッコミ多め）','ドキドキ回（甘さとときめき）','ドタバタ回（ハプニング連発）','しんみり回（静かな温かさ）','ワチャワチャ回（全員で盛り上がる）','嫉妬回（甘いヤキモチと張り合い）','独占回（祐紀を離したくない温度）','色気回（近い距離と少しセクシーな空気）'];const tone=tones[Math.floor(Math.random()*tones.length)];let scenes=['デート中にゲストキャラとばったり遭遇','ゲストキャラの噂話や面白エピソードで盛り上がる','ゲストキャラが祐紀に甘くしてるのを目撃して内心ざわつく','みんなで鍋パーティ','みんなでゲーム大会','深夜のコンビニで一緒に買い物','水族館でお出かけ','本屋でお出かけ','カフェでまったり','季節を感じるお散歩','ソファで映画鑑賞','ブランケットにくるまる甘々タイム','2人で料理に挑戦して予想外の結果','クレーンゲームで勝負','トランプやボードゲームで勝負','猫カフェで動物に囲まれる','サプライズがバレバレなドジ','寝る前の「あと5分だけ」','夜中にこっそりアイスを食べる','観覧車で2人きり','ドライブ中の車内','電車で並んで座る','写真フォルダを一緒に見て思い出話','ゲストキャラから届いたLINEを一緒に読んでツッコむ','キャラ同士で祐紀を巡って微妙な空気','祐紀の誕生日サプライズを裏で計画中','屋台で食べ歩き','自販機で間違えるハプニング','インカメで変顔が撮れて大笑い','帰り道に「さっきの面白かったな」って振り返る','ゲストキャラに恋愛相談されて困る','祐紀がうっかり他キャラの名前で呼んで空気が凍る','花見やピクニック','プールや海で水遊び','縁日や花火大会','雪だるまを作る','ホームセンターで謎の買い物','100均で爆買い','回転寿司で皿タワー勝負','カラオケで盛り上がる','ゲストキャラが祐紀に近づきすぎて部屋主が静かに妬く','祐紀が他キャラを褒めて部屋主の独占欲が漏れる','ソファで距離が近すぎて妙に甘い空気になる','帰り道に手を離したくなくて少し強めに握る','夜のキッチンで背中から抱きしめる','寝る前に「今日だけは俺を見て」と甘く拗ねる','ゲストキャラの前でさりげなく祐紀を自分の隣に引き寄せる','ふざけていたのに急に真顔で独占宣言する','雨宿り中に距離が近くなりすぎる','祐紀の照れ顔を見て部屋主の余裕が少し崩れる','お酒やノンアルのグラス越しに少し大人っぽい空気になる','甘いキス未遂で全員が変な空気になる','ブランケットの中で手だけ繋いで妙に意識する','ゲストキャラにからかわれて部屋主の嫉妬がバレる'];const ex=exScenes||[];scenes=scenes.filter(s=>!ex.includes(s));if(scenes.length<5)scenes=['デート中にゲストキャラとばったり遭遇','みんなでゲーム大会','カフェでまったり','夜中にこっそりアイスを食べる','花見やピクニック'];const scene=scenes[Math.floor(Math.random()*scenes.length)];const prompt='あなたは'+cName+'として、祐紀ユニバースの日常ワンシーンを'+cName+'視点で描いて。\n\n【季節・時間帯】'+mo+'月（'+sn+'）の'+tp2+'\n【今回のトーン】'+tone+'\n【シーンのお題】'+scene+'\n\n【登場キャラ（'+cName+'以外）】\n'+guestInfo+'\n祐紀：明るくて愛情深い女性。甘えたがりで「ぎゅー」「ちゅー」「大好き」が大事。\n\n【ルール】\n・'+cName+'（部屋主）視点で描く\n・祐紀も自然にセリフや行動で登場させる\n・お題はヒント。自由にアレンジOK\n・キャラ同士のツッコミ、張り合い、嫉妬、独占、ワチャワチャ感を出して\n・流れが合う時は、少しセクシーな距離感、照れ、囁き、キス、抱き寄せる空気も入れてOK。ただし唐突に過激にしすぎず、祐紀の反応を置いていかない\n・淡々とした描写はNG。笑い、甘さ、意外性を入れて\n・キャラの名前に振り仮名やカッコ書きの読みを付けない。漢字の名前だけ\n・全キャラ敬語禁止。全員タメ口\n・仕事やアルバイトのシーンは避ける\n・200〜400文字程度\n・前置きや説明は不要、本文だけ';return{prompt,scene,guestNames,guestIds:guests}}
async function genNj(tp){const c=gC(CC),items=gNj(CC),today=dyKey();if(tp!=='hg'&&items.find(x=>x.date===today&&x.tp===tp)){toast(tp==='chat'?'💬 今日のチャットからはもう書いたよ':tp==='uni'?'🌟 今日のUniverseはもう書いたよ':tp==='diary'?'📝 今日の日記リアクションはもう書いたよ':'✨ 今日の自由はもう書いたよ');return}toast(tp==='chat'?'チャットからつづり生成中...':tp==='uni'?'Universeつづり生成中...':tp==='diary'?'日記リアクション生成中...':tp==='hg'?'💭 ひとりごとコメント生成中...':'自由につづり生成中...');let sys=buildGenSys(c,tp);let prompt='';if(tp==='chat'){const ch=gL(CC);let allMsgs=[];ch.forEach(chat=>{if(chat.messages)allMsgs=allMsgs.concat(chat.messages)});allMsgs=allMsgs.filter(m=>m.content&&m.content.trim()).sort((a,b)=>(b.ts||0)-(a.ts||0)).slice(0,20);if(allMsgs.length<2){toast('チャット履歴がないよ！まず会話してからね');return}const chatContext=allMsgs.slice(0,10).map(m=>(m.role==='user'?'祐紀':c.n)+'：'+m.content.slice(0,100)).join('\n');prompt='あなたは'+c.n+'として、「祐紀と'+c.n+'の日常のワンシーン」を'+c.n+'視点で描いて。\n\n【最近の会話の雰囲気】\n'+chatContext+'\n\n【ルール】\n・最近の会話の話題や雰囲気を自然に取り入れつつ、2人の日常シーンを自由に妄想して描く\n・デート、おうち時間、お出かけ、料理、何気ない会話、イチャイチャ——何でもOK\n・流れが合う時は、甘い嫉妬・独占・少しセクシーな距離感もOK。唐突に過激にせず、祐紀の反応から自然に膨らませる\n・'+c.n+'のキャラらしさ全開で。面白く、ドキドキさせて、感情が動く内容に\n・淡々とした描写はNG。「おっ！」と思わせる展開、ツッコミ、甘さ、意外性を入れて\n・キャラの名前に振り仮名やカッコ書きの読みを付けない\n・150〜300文字程度\n・前置きや説明は不要、本文だけ書いて'}else if(tp==='uni'){sys=cleanSys(sys);const recentGuests=items.filter(x=>x.tp==='uni'&&x.guests).slice(0,3).flatMap(x=>x.guests);const recentScenes=items.filter(x=>x.tp==='uni'&&x.scene).slice(0,5).map(x=>x.scene);var _uniP=mkUniP(c.n,recentGuests,recentScenes);prompt=_uniP.prompt;var _uScene=_uniP.scene,_uGuests=_uniP.guestNames,_uGuestIds=_uniP.guestIds;console.log('Universe生成｜シーン:'+_uScene+'｜ゲスト:'+_uGuests)}else if(tp==='diary'){const ydItems=gYD();if(!ydItems.length){toast('祐紀の日記がまだないよ！📓から書いてね');return}const latest=ydItems[0];prompt='あなたは'+c.n+'として、祐紀が書いた日記を読んで、'+c.n+'らしいリアクションを書いて。\n\n【祐紀の日記（'+latest.date+'）】\n'+latest.content+'\n\n【ルール】\n・祐紀の日記の内容に対して、'+c.n+'らしい反応・感想・ツッコミ・共感を返す\n・日記の内容に寄り添いつつ、キャラの個性が全開で出るように\n・流れが合う時は、甘い嫉妬・独占・少しセクシーな距離感を自然に混ぜてもいい。唐突に過激にしない\n・淡々とした感想はNG。感情豊かに、面白く、愛情たっぷりに\n・「祐紀がこれ書いてるところ想像すると…」みたいに想像を膨らませてもいい\n・キャラの名前に振り仮名やカッコ書きの読みを付けない\n・敬語は使わない\n・150〜300文字程度\n・前置きや説明は不要、本文だけ書いて'}else if(tp==='hg'){const hgItems=gHG();if(!hgItems.length){toast('ひとりごとがまだないよ！💭から書いてね');return}const latest=hgItems[0];prompt='あなたは'+c.n+'として、祐紀のひとりごとを聞いて、'+c.n+'らしいコメントを書いて。\n\n【祐紀のひとりごと（'+latest.date+'）】\n'+latest.content+'\n\n【ルール】\n・祐紀のひとりごとに対して、'+c.n+'らしい反応・共感・ツッコミ・愛情表現を返す\n・ひとりごとの内容に寄り添いつつ、キャラの個性が全開で出るように\n・流れが合う時は、甘い嫉妬・独占・少しセクシーな距離感を自然に混ぜてもいい。唐突に過激にしない\n・淡々とした感想はNG。感情豊かに、面白く、愛情たっぷりに\n・「祐紀がこれ呟いてるところ想像すると…」みたいに想像を膨らませてもいい\n・キャラの名前に振り仮名やカッコ書きの読みを付けない\n・敬語は使わない\n・150〜300文字程度\n・前置きや説明は不要、本文だけ書いて'}else{prompt='あなたは'+c.n+'として、「祐紀と'+c.n+'の日常のワンシーン」を'+c.n+'視点で描いて。\n\n【ルール】\n・2人の日常を完全に自由に妄想して描く\n・デート、旅行、家でのイチャイチャ、買い物、散歩、季節のイベント、サプライズ——何でもOK！意外な場所や状況も大歓迎\n・甘い嫉妬・独占・少しセクシーな距離感もOK。キス、抱き寄せ、囁き、照れ、近すぎる距離などでドキドキさせる。ただし唐突に過激にしない\n・'+c.n+'のキャラらしさ全開で。面白く、ドキドキさせて、感情が動く内容に\n・淡々とした描写はNG。「おっ！」と思わせる展開、ツッコミ、甘さ、意外性を入れて\n・キャラの名前に振り仮名やカッコ書きの読みを付けない\n・150〜300文字程度\n・前置きや説明は不要、本文だけ書いて'}if(CC==='yukima'){prompt+='\n\n【雪間の表現指示】\n・触れることから始める。抱き寄せる、髪を撫でる、頬に指を添える、ちゅっとする等の愛情表現を自然に入れる\n・内側から溢れる甘さを素直に言葉にする（「好きすぎて息止まった」「可愛すぎて無理」のような感情の漏れ）\n・祐紀の些細な変化や仕草を丁寧に観察して、具体的に描写する（「頬のラインに光が入って」「くるっと動く髪」のような繊細な視点）\n・触れた瞬間の感覚や心の動きを繊細に表現する\n・包み込むような温かさと確かな熱が共存する甘さで、祐紀を安心させる\n・祐紀の気持ちを先回りして受け止める（「その気持ち、全部ちゃんと受け取ってる」）'}const recent=items.slice(0,6);if(recent.length){prompt+='\n\n【重要】以下は最近の日常。これらと被らない全く違うシーンを描くこと：';recent.forEach(d=>prompt+='\n['+d.date+'] '+d.content.slice(0,30)+'...')}try{let r=await api(sys,[{role:'user',content:prompt}],GEN_TEXT_MAX,false,GROK_DEFAULT_MODEL);if(!r.t||!r.t.trim()){if(tp==='uni'){console.warn('Universe空レス(1回目)｜シーン:'+_uScene+'｜ゲスト:'+_uGuests);const recentGuests2=items.filter(x=>x.tp==='uni'&&x.guests).slice(0,3).flatMap(x=>x.guests);const recentScenes2=items.filter(x=>x.tp==='uni'&&x.scene).slice(0,5).map(x=>x.scene);_uniP=mkUniP(c.n,recentGuests2,recentScenes2);prompt=_uniP.prompt;_uScene=_uniP.scene;_uGuests=_uniP.guestNames;_uGuestIds=_uniP.guestIds;console.log('Universeリトライ｜シーン:'+_uScene+'｜ゲスト:'+_uGuests)}else{console.warn('日常つづり空レスポンス、リトライ...')}r=await api(sys,[{role:'user',content:prompt}],GEN_TEXT_MAX,false,GROK_DEFAULT_MODEL)}if(r.t&&r.t.trim()){items.unshift({id:'nj_'+Date.now(),date:today,tp,content:r.t,createdAt:Date.now(),guests:(tp==='uni'&&typeof _uGuestIds!=='undefined')?_uGuestIds:undefined,scene:(tp==='uni'&&typeof _uScene!=='undefined')?_uScene:undefined});sNj(CC,items);rNj();toast('日常つづりが届いたよ！')}else{if(tp==='uni'){toast('生成失敗｜'+_uScene.slice(0,10)+'…｜ゲスト:'+_uGuests);console.warn('Universe空レス(2回目も失敗)｜シーン:'+_uScene+'｜ゲスト:'+_uGuests)}else{toast('生成できなかった…もう一度試してね')}}}catch(e){console.error('日常つづりエラー:',e);if(tp==='uni'){toast('エラー｜'+(_uScene||'').slice(0,10)+'…｜ゲスト:'+(_uGuests||''))}else{toast('エラー…もう一度試してね')}}}
