async function api(sys,msgs,mt,tk,mdl){
const key=localStorage.getItem('yu_k'),baseModel=normModel(mdl||localStorage.getItem('yu_m')||GROK_DEFAULT_MODEL);
if(!key)throw new Error('APIキー未設定');
const TOKEN_CHAR_LIMIT=18000;
const valid=msgs.filter(m=>m.content&&m.content.trim());
let recent=valid.slice(-(MH*2));
const sysLen=(sys||'').length;
let totalLen=sysLen;
for(const m of recent){totalLen+=(m.content||'').length+((m.fileTxt||'').length||0)}
while(recent.length>4&&totalLen>TOKEN_CHAR_LIMIT){totalLen-=((recent[0].content||'').length+((recent[0].fileTxt||'').length||0));recent=recent.slice(1)}
while(recent.length>0&&recent[0].role==='assistant')recent=recent.slice(1);
async function buildMapped(model){
 const mapped=[];
 const allowVision=supportsVisionModel(model);
 for(let idx=0;idx<recent.length;idx++){
  const m=recent[idx];
  const isLatestUser=idx===recent.length-1||(idx===recent.length-2&&recent[recent.length-1].role==='assistant');
  const images=(allowVision?(m.imgs||(m.img?[m.img]:[])):[]);
  const ft=isLatestUser?clipTxt(m.fileTxt||'',12000):null;
  const baseText=clipTxt(m.content||'',4000);
  if(images.length||ft){
   const ct=[];
   for(const im of images){
    let url='';
    if(im.k){try{const data=await loadImg(im.k);if(data){url=data.startsWith('data:')?data:'data:image/jpeg;base64,'+data}}catch{}}
    else if(im.d){url='data:image/jpeg;base64,'+im.d}
    if(url)ct.push({type:'image_url',image_url:{url}})
   }
   if(ft)ct.push({type:'text',text:'【添付ファイル】\n'+ft});
   if(baseText&&baseText!=='（画像）'&&baseText!=='（添付）'&&baseText!=='（ファイル）')ct.push({type:'text',text:baseText});
   if(ct.length>0){mapped.push({role:'user',content:ct})}
   else{mapped.push({role:m.role,content:baseText||'（画像を送信）'})}
  }else{
   mapped.push({role:m.role,content:baseText})
  }
 }
 return mapped;
}
let lastErr=null;
for(const tryModel of modelFallbacks(baseModel)){
 try{
  const mapped=await buildMapped(tryModel);
  const body={model:tryModel,max_tokens:mt||1024,messages:[{role:'system',content:clipTxt(sys||'',9000)},...mapped]};
  /* reasoning_effort は公式上 grok-4.3 用。4.20系には送らない */
  if(tryModel==='grok-4.3')body.reasoning_effort=tk?'low':'none';
  const res=await fetch(GROK_API_URL,{method:'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+key},body:JSON.stringify(body)});
  if(!res.ok){
   const text=await res.text().catch(()=>'');
   let msg=text;
   try{const e=JSON.parse(text);msg=e.error?.message||e.message||text}catch{}
   const err=new Error(`${res.status}:${msg||'API error'}`);err.status=res.status;throw err;
  }
  const data=await res.json();
  const msg=data.choices?.[0]?.message||{};
  let content='';
  if(typeof msg.content==='string')content=msg.content;
  else if(Array.isArray(msg.content))content=msg.content.map(x=>typeof x==='string'?x:(x.text||x.content||'')).join('\n').trim();
  const reasoning=msg.reasoning_content||msg.reasoning||null;
  const actualModel=data.model||tryModel;
  return{tk:tk?reasoning:null,t:content,m:actualModel}
 }catch(e){lastErr=e;console.warn('Grok API retry candidate failed:',tryModel,e.message||e);continue}
}
if(lastErr&&String(lastErr.message||'').toLowerCase().includes('type'))throw new Error('通信失敗：モデル名かCORS/ネットワークの可能性');
throw lastErr||new Error('API通信失敗')
}
