function initWpSec(){document.getElementById('wpSecBody').style.display='none';document.getElementById('wpSecArr').style.transform='';const th=gTh(CC);const cw=document.getElementById('thCW');cw.innerHTML=th.cw?'読込中...':'タップして画像を選択';cw.dataset.val=th.cw||'';if(th.cw){loadImg(th.cw).then(data=>{if(data){cw.innerHTML=`<img src="${data}">`;cw.dataset.pv=data}})}document.getElementById('thCR').style.display=th.cw?'inline-block':'none';const co=th.co!==undefined?th.co:18;document.getElementById('coRg').value=co;document.getElementById('coVal').textContent=co;const el=document.getElementById('thCB');el.innerHTML='';const bgc=['#1a1614','#211e1b','#2a2623','#0d1117','#1a1a2e','#16213e','#1b1b2f','#0f0e17','#2d132c','#1e1e1e','#f5f2ee','#faf8f5','#fff8f0','#f0f4f8'];bgc.forEach(c=>{const isSel=th.cb===c;const s=document.createElement('div');s.style.cssText=`width:26px;height:26px;border-radius:50%;cursor:pointer;border:2px solid ${isSel?'var(--ac)':'transparent'};background:${c};flex-shrink:0`;if(isSel)s.dataset.sel='1';s.onclick=()=>{el.querySelectorAll('div').forEach(x=>{x.style.borderColor='transparent';delete x.dataset.sel});s.style.borderColor='var(--ac)';s.dataset.sel='1';delete document.getElementById('thR').dataset.custom;const rgb=h2rgb(c);document.getElementById('thR').value=rgb[0];document.getElementById('thG').value=rgb[1];document.getElementById('thB').value=rgb[2];document.getElementById('thCCpv').style.background=c;document.getElementById('thCCh').textContent=c};el.appendChild(s)});const col=th.cb||'#1a1614';const rgb=h2rgb(col);document.getElementById('thR').value=rgb[0];document.getElementById('thG').value=rgb[1];document.getElementById('thB').value=rgb[2];document.getElementById('thCCpv').style.background=col;document.getElementById('thCCh').textContent=col;if(th.cb&&!bgc.includes(th.cb))document.getElementById('thR').dataset.custom='1';else delete document.getElementById('thR').dataset.custom}
function sWpSet(){const th=gTh(CC);const cw=document.getElementById('thCW');if(cw.dataset.val!==undefined&&cw.dataset.val!=='')th.cw=cw.dataset.val;else if(!cw.querySelector('img'))delete th.cw;th.co=parseInt(document.getElementById('coRg').value);const hasSel=document.querySelector('#thCB div[data-sel="1"]');if(hasSel){th.cb=r2h(hasSel.style.background)}else if(document.getElementById('thR').dataset.custom){const r=document.getElementById('thR').value,g=document.getElementById('thG').value,b=document.getElementById('thB').value;th.cb='#'+[r,g,b].map(x=>(+x).toString(16).padStart(2,'0')).join('')}sTh(CC,th);apTh3();toast('壁紙保存！')}
function apTh2(){const s2=document.getElementById('s2'),old=s2.querySelector('.wp-layer');if(old)old.remove();s2.classList.remove('themed');s2.style.removeProperty('--s2card');const th=gTh(CC);if(th.rw){s2.classList.add('themed');const layer=document.createElement('div');layer.className='wp-layer';layer.style.opacity=(th.ro!==undefined?th.ro:18)/100;s2.insertBefore(layer,s2.firstChild);loadImg(th.rw).then(data=>{if(data)layer.style.backgroundImage=`url(${data})`});const to=(th.to!==undefined?th.to:80)/100;const lt=getThemeMode()!=='d';const cb=lt?[255,255,255]:[42,38,35];s2.style.setProperty('--s2card',`rgba(${cb[0]},${cb[1]},${cb[2]},${to})`)}}
function apTh3(){const s3=document.getElementById('s3'),old=s3.querySelector('.wp-layer');if(old)old.remove();s3.classList.remove('themed');s3.style.background='';const ms=document.getElementById('ms');ms.style.background='';const th=gTh(CC);if(th.cb)s3.style.background=th.cb;if(th.cw){s3.classList.add('themed');const layer=document.createElement('div');layer.className='wp-layer';layer.style.opacity=(th.co!==undefined?th.co:18)/100;s3.insertBefore(layer,s3.firstChild);loadImg(th.cw).then(data=>{if(data)layer.style.backgroundImage=`url(${data})`})}}
