function tGS(){const w=document.getElementById('gsW'),i=document.getElementById('gsI');if(w.style.display==='none'){w.style.display='';i.focus()}else{w.style.display='none';i.value='';document.getElementById('gsR').style.display='none'}}
function doGS(){const q=document.getElementById('gsI').value.trim().toLowerCase(),el=document.getElementById('gsR');if(!q){el.style.display='none';return}el.style.display='';el.innerHTML='';let found=false;gOr().forEach(id=>{if(!DC[id])return;const c=gC(id),chats=gL(id);chats.forEach(ch=>{const matches=ch.messages.filter(m=>m.content.toLowerCase().includes(q));if(matches.length||ch.title.toLowerCase().includes(q)){found=true;const div=document.createElement('div');div.className='gsr-ri';div.onclick=()=>{el.style.display='none';document.getElementById('gsI').value='';document.getElementById('gsW').style.display='none';oR(id);setTimeout(()=>oC(ch.id),50)};const preview=matches.length?matches[0].content.slice(0,60):'';div.innerHTML=`<div class="gsr-cn">${X(c.n)}</div><div class="lt">${X(ch.title)}</div>${preview?`<div class="lp">${X(preview)}</div>`:''}`;el.appendChild(div)}})});if(!found)el.innerHTML='<div style="text-align:center;color:var(--t3);padding:16px;font-size:12px">見つからなかった</div>'}
