function tMsgSr(){const w=document.getElementById('msgSrW'),i=document.getElementById('msgSrI');if(w.style.display==='none'){w.style.display='';i.value='';document.getElementById('msgSrR').style.display='none';i.focus()}else{w.style.display='none';i.value='';document.getElementById('msgSrR').style.display='none';document.querySelectorAll('#ms .m.sr-hl').forEach(m=>m.classList.remove('sr-hl'))}}
function doMsgSr(){const q=document.getElementById('msgSrI').value.trim().toLowerCase(),el=document.getElementById('msgSrR');if(!q||q.length<2){el.style.display='none';return}el.style.display='';el.innerHTML='';const ch=gCC();if(!ch||!ch.messages)return;const c=gC(CC);const hits=[];ch.messages.forEach((m,i)=>{if(m.content&&m.content.toLowerCase().includes(q)){hits.push({m,i})}});if(!hits.length){el.innerHTML='<div style="text-align:center;color:var(--t3);padding:12px;font-size:12px">見つからなかった</div>';return}const maxShow=Math.min(hits.length,30);const shown=hits.slice(-maxShow);shown.forEach(({m,i})=>{const div=document.createElement('div');div.className='msr-ri';const who=m.role==='user'?'祐紀':c.n;const txt=m.content.length>80?m.content.slice(0,80)+'…':m.content;const esc=X(txt);const ql=q.replace(/[.*+?^${}()|[\]\\]/g,'\\$&');const hl=esc.replace(new RegExp('('+ql+')','gi'),'<mark>$1</mark>');const ts=m.ts?fmTs(m.ts):'';div.innerHTML=`<div class="msr-who">${who}</div><div class="msr-txt">${hl}</div>${ts?`<div class="msr-ts">${ts}</div>`:''}`;div.onclick=()=>scrollToMsg(m.ts);el.appendChild(div)});if(hits.length>maxShow){el.insertAdjacentHTML('beforeend',`<div style="text-align:center;color:var(--t3);padding:8px;font-size:11px">他${hits.length-maxShow}件</div>`)}}
function scrollToMsg(ts){if(!ts)return;document.getElementById('msgSrW').style.display='none';document.getElementById('msgSrI').value='';document.getElementById('msgSrR').style.display='none';document.querySelectorAll('#ms .m.sr-hl').forEach(m=>m.classList.remove('sr-hl'));const target=document.querySelector(`#ms .m[data-ts="${ts}"]`);if(target){target.scrollIntoView({behavior:'smooth',block:'center'});target.classList.add('sr-hl');setTimeout(()=>target.classList.remove('sr-hl'),3000)}}
const LK_PIN='0415',LK_HINT='GPT start';let lkInput='',lkFail=0;
function initLock(){const pad=document.getElementById('lkPad');pad.innerHTML='';[1,2,3,4,5,6,7,8,9].forEach(n=>{const b=document.createElement('button');b.className='lk-key';b.textContent=n;b.onclick=()=>lkPress(String(n));pad.appendChild(b)});const del=document.createElement('button');del.className='lk-del';del.textContent='削除';del.onclick=lkDel;pad.appendChild(del);const zero=document.createElement('button');zero.className='lk-key lk-zero';zero.textContent='0';zero.onclick=()=>lkPress('0');pad.appendChild(zero);const sp=document.createElement('div');pad.appendChild(sp)}
function lkPress(n){if(lkInput.length>=4)return;lkInput+=n;updLkDots();if(lkInput.length===4)setTimeout(chkLk,200)}
function lkDel(){if(!lkInput.length)return;lkInput=lkInput.slice(0,-1);updLkDots()}
function updLkDots(){document.querySelectorAll('#lkDots .lk-dot').forEach((d,i)=>{d.classList.toggle('filled',i<lkInput.length);d.classList.remove('err')})}
function chkLk(){if(lkInput===LK_PIN){document.querySelectorAll('#lkDots .lk-dot').forEach(d=>{d.style.background='#72c4a0';d.style.borderColor='#72c4a0';d.style.boxShadow='0 0 10px rgba(114,196,160,.5)'});setTimeout(()=>{if(localStorage.getItem('yu_k'))goS1();else{document.querySelectorAll('.S').forEach(s=>s.classList.remove('A'));document.getElementById('s0').classList.add('A')}},400)}else{lkFail++;lkInput='';document.querySelectorAll('#lkDots .lk-dot').forEach(d=>{d.classList.remove('filled');d.classList.add('err')});setTimeout(()=>document.querySelectorAll('#lkDots .lk-dot').forEach(d=>d.classList.remove('err')),400);if(lkFail>=5)document.getElementById('lkHint').textContent='ヒント：'+LK_HINT}}
document.addEventListener('DOMContentLoaded',()=>{apThemeMode(getThemeMode());thk=localStorage.getItem('yu_tk')==='1';document.getElementById('ci').addEventListener('input',function(){ag(this)});const ok=localStorage.getItem('yuki_api_key')||localStorage.getItem('yu_key')||localStorage.getItem('yu_k');if(ok&&!localStorage.getItem('yu_k'))localStorage.setItem('yu_k',ok);const storedModel=localStorage.getItem('yu_m');if(!storedModel||storedModel==='grok-4.3'||storedModel==='grok-4.20-non-reasoning'||normModel(storedModel)!==storedModel)localStorage.setItem('yu_m',GROK_DEFAULT_MODEL);if(localStorage.getItem('yu_k')){document.querySelectorAll('.S').forEach(s=>s.classList.remove('A'));document.getElementById('sLock').classList.add('A');initLock()}document.getElementById('ms').addEventListener('scroll',updChatFabs,{passive:true});updChatFabs();migrateToIDB().catch(e=>console.warn('Migration:',e));if('serviceWorker'in navigator){navigator.serviceWorker.getRegistrations().then(regs=>{regs.forEach(r=>r.unregister())})}});